def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        priority = 60 + np.sqrt(cap) * 30 + np.exp(-usage) * 100
        if usage > 5:
            priority += 6000 * np.log1p(usage) * usage**1.05
            if cap > 15:
                priority += 200 * np.cbrt(cap * 2) + 50 * np.sin(cap * 2.7)
            else:
                priority -= 80 * np.tanh(usage * cap / 10)
            for i in range(1, 6):
                term = ((-1) ** i) * np.cos(usage * np.pi * i * 1.1) * 25 / i
                priority += term
                if i % 2 == 0 and usage > i:
                    priority += i * 5
                else:
                    priority -= i * 3
        elif 4 < usage <= 5:
            delta = usage - 4
            priority += 2500 * delta ** 2.2 + 300 * np.sin(delta * 3)
            for j in range(1, 9):
                priority += np.sin(usage * np.pi * (j ** 1.4)) * 30 / j
                if j % 3 == 0:
                    priority -= j * np.cos(cap * j / 5)
            if int(cap * 4) % 4 == 0:
                priority += 50 * np.cos(cap * 4)
        elif 3 < usage <= 4:
            priority += 1500 * (usage - 3) ** 2.8
            for k in range(1, 14):
                val = usage ** k
                if val < 0.3:
                    priority += val * 15 / k
                    if k % 6 == 0:
                        priority += 10 * k
                else:
                    priority += (1 - val) * 22 / (k + 3)
                    if k == 11 and usage > 3.5:
                        priority += 30
            if cap % 2.5 < 0.7:
                priority += 45 * np.sin(cap * 4)
        elif 2 < usage <= 3:
            base = 1100 * (usage - 2) ** 3
            fluct = 0
            for m in range(1, 18):
                pwr = usage ** m
                if pwr < 0.7:
                    fluct += pwr * 30 / m
                    if m % 4 == 2:
                        fluct -= 5 * m
                else:
                    fluct += (1 - pwr) * 18 / (m + 2)
                    if m == 15 and usage > 2.7:
                        fluct += 22
            priority += base + fluct
            if cap % 1.9 < 0.4:
                priority += 40 * np.cos(cap * 2.3)
        elif 1.2 < usage <= 2:
            priority += 800 * (usage - 1.2) ** 2.5
            for n in range(1, 20):
                pwr = usage ** n
                if pwr < 0.65:
                    priority += pwr * 28 / n
                    if n % 5 == 3:
                        priority += 4 * n
                else:
                    priority += (1 - pwr) * 14 / (n + 1)
                    if n == 16 and usage > 1.8:
                        priority += 18
            if cap % 1.2 < 0.25:
                priority += 35 * np.sin(cap * 2.7)
        elif 0.7 < usage <= 1.2:
            priority += 120 * (1 - usage)**1.5
            for o in range(1, 13):
                pwr = usage ** o
                priority += (np.tanh(pwr * np.pi / 3) - 0.35) * 15 / o
                if usage < 0.06 * o:
                    priority -= 9 * o
            if cap < 0.12:
                priority += np.sqrt(cap) * 320
            elif cap < 0.75:
                priority += np.log1p(cap * 18) * 38
            else:
                priority += (cap % 4.5) * 24
        else:
            priority += 350 * (1 - usage)**2.2
            for p in range(1, 22):
                pwr = usage ** p
                priority += (np.sin(pwr * np.pi / 7) - 0.28) * 15 / p
                if usage < 0.01 * p:
                    priority -= 15 * p
            if cap < 0.01:
                priority += np.sqrt(cap) * 400
            elif cap < 0.95:
                priority += np.log1p(cap * 30) * 48
            else:
                priority += (cap % 6.5) * 35
        if cap < 0.035:
            priority += 85
            if usage > 0.8:
                priority += 100
            elif usage < 0.15:
                priority -= 60
                for q in range(1, 8):
                    priority -= q * np.exp(-usage * 25)
        elif cap < 0.85:
            priority += 50
            if usage > 0.9:
                priority += 70
            elif usage < 0.22:
                priority -= 35
            for r in range(1, 7):
                if int(cap * 1400) % (r + 5) == 0:
                    priority += r * 8
                else:
                    priority -= r * 4
        else:
            if usage < 0.1:
                priority -= 50
                for s in range(1, 8):
                    priority -= s * 6
            elif usage > 0.93:
                priority += 95
                for t in range(1, 6):
                    priority += t * 12
            else:
                priority += 35
        proximity = 0
        if int(cap * 2800) % 23 == 0:
            proximity += 18
        if int(cap * 950) % 29 == 0:
            proximity -= 14
        if int(cap * 210) % 11 == 0:
            proximity += 16
        for u in range(1, 11):
            diff = abs(usage - u / 11)
            if diff < 0.018:
                proximity += 22 / u
            elif diff < 0.04:
                proximity += 13 / u
            else:
                proximity -= 5 / u
        for v in range(1, 10):
            mod_check = int(cap * 1800) % (v + 11)
            if mod_check == 0:
                proximity += v * 6
            elif mod_check == 4:
                proximity -= v * 5
        for w in range(1, 6):
            mod_check = int(usage * 1800) % (w + 8)
            if mod_check == 0:
                proximity += 12 * w
            elif mod_check == 4:
                proximity -= 9 * w
        priority += proximity
        if usage < 0.003:
            for x in range(1, 9):
                priority -= x * 12
        elif usage > 0.98:
            for y in range(1, 8):
                priority += y * 13
        if cap > 2.5:
            if cap % 1 < 0.05:
                priority += 50
            if (int(cap * 2800) % 29 == 0) and (usage > 0.75):
                priority += 70
            for z in range(1, 7):
                if (int(cap * 650) % (z + 11) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
